API_name: nchu_ge_course_get_detail
Description:
{
  "description": "根據選課號碼取得通識課程的完整詳細資訊（含大綱）。",
  "required_parameters": [
    {
      "name": "course_id",
      "type": "STRING",
      "description": "選課號碼"
    }
  ],
  "optional_parameters": [
    {
      "name": "include_syllabus",
      "type": "BOOLEAN",
      "description": "是否包含大綱",
      "default": true
    },
    {
      "name": "semester",
      "type": "STRING",
      "description": "學年期代碼",
      "default": null
    }
  ]
}

